SELECT * FROM t_meeting_tag WHERE meeting_id IN
#{meetingId}
AND is_deleted = 0

SELECT mt.tag_id AS tagId, COUNT(DISTINCT mt.meeting_id) AS newMeetingCount FROM t_meeting_tag mt INNER JOIN t_meeting m ON mt.meeting_id = m.meeting_id AND m.is_deleted = 0 WHERE mt.tag_id IN
#{tagId}
AND mt.is_deleted = 0 AND m.create_time >= #{since} GROUP BY mt.tag_id
